#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, X; scanf("%lld %lld", &N, &X);
        long long lo = (X + 2) / 3;               // ceil(X/3)
        long long hi = (N + X) / 4;               // floor((N+X)/4)
        if(lo <= hi){
            long long A = lo;
            long long B = 3 * A - X;
            long long C = N - A - B;
            printf("YES\n%lld %lld %lld\n", A, B, C);
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

